<?php
namespace App\Models;
use App\Enums\ReconciliationStatus;use App\Models\Concerns\BelongsToTenant;use App\Models\Concerns\HasAuditTrail;use Illuminate\Database\Eloquent\Concerns\HasUlids;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\HasMany;
class BankReconciliation extends Model{use BelongsToTenant,HasAuditTrail,HasUlids;protected $fillable=['cooperative_id','cooperative_bank_account_id','statement_start_date','statement_end_date','opening_balance_minor','closing_balance_minor','status','prepared_by','completed_by','completed_at'];protected function casts():array{return ['statement_start_date'=>'date','statement_end_date'=>'date','opening_balance_minor'=>'integer','closing_balance_minor'=>'integer','status'=>ReconciliationStatus::class,'completed_at'=>'datetime'];}public function bankAccount():\Illuminate\Database\Eloquent\Relations\BelongsTo{return $this->belongsTo(CooperativeBankAccount::class,'cooperative_bank_account_id');}public function statementLines():HasMany{return $this->hasMany(BankStatementLine::class);}}
